BasicProperties.ActionCode:
if(b_isCompanyUIResultsUI){
	f_setAllCharts();
	if(checkbox_KPISummary.isSelected()){
		gr_chartKPISummary_presentation.setVisible(true);
	}
	else{
		gr_chartKPISummary_presentation.setVisible(false);
	}
}
else{
	f_showCorrectChart();
}
